 1	import React, { FC, useMemo } from 'react';
 2	
 3	import SubTitleChartLabel from '@kubevirt-utils/components/Charts/ChartLabels/SubTitleChartLabel';
 4	import TitleChartLabel from '@kubevirt-utils/components/Charts/ChartLabels/TitleChartLabel';
 5	import { AlertsByHealthImpact } from '@kubevirt-utils/hooks/useInfrastructureAlerts/useInfrastructureAlerts';
 6	import { t } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { isEmpty } from '@kubevirt-utils/utils/utils';
 8	import { ChartDonut } from '@patternfly/react-charts';
 9	
10	import { alertTypeToColorMap } from '../utils/utils';
11	
12	import EmptyStateNoAlerts from './EmptyStateNoAlerts';
13	
14	type HealthPopupChartProps = {
15	  alerts: AlertsByHealthImpact;
16	  numberOfAlerts?: number;
17	};
18	
19	const HealthPopupChart: FC<HealthPopupChartProps> = ({ alerts, numberOfAlerts }) => {
20	  const totalNumberAlerts = useMemo(
21	    () => Object.values(alerts)?.reduce((acc, alertType) => acc + (alertType?.length || 0), 0),
22	    [alerts],
23	  );
24	
25	  const chartData = useMemo(
26	    () =>
27	      Object.keys(alerts)?.reduce((acc, alertType) => {
28	        const numAlertsForType: number = alerts[alertType]?.length;
29	        const percentage: number = Math.round((numAlertsForType / totalNumberAlerts) * 100);
30	        acc.push({
31	          fill: alertTypeToColorMap[alertType],
32	          x: alertType,
33	          y: percentage,
34	        });
35	        return acc;
36	      }, []),
37	    [alerts, totalNumberAlerts],
38	  );
39	
40	  if (isEmpty(numberOfAlerts))
41	    return <EmptyStateNoAlerts classname="kv-health-popup__empty-state--no-alerts" />;
42	
43	  return (
44	    <div className="kv-health-popup__chart">
45	      <ChartDonut
46	        style={{
47	          data: {
48	            fill: ({ datum }) => datum?.fill,
49	          },
50	        }}
51	        ariaDesc={t('Virtualization Alerts')}
52	        ariaTitle={t('Virtualization Alerts donut chart')}
53	        data={chartData}
54	        height={150}
55	        labels={({ datum }) => `${datum?.x}: ${datum?.y}%`}
56	        subTitle={t('Alerts')}
57	        subTitleComponent={<SubTitleChartLabel />}
58	        title={totalNumberAlerts?.toString()}
59	        titleComponent={<TitleChartLabel />}
60	        width={150}
61	      />
62	    </div>
63	  );
64	};
65	
66	export default HealthPopupChart;

